{"file_path":"core/common/test/ReproductionTest.kt","content":"package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class ReproductionTest {
    private val readableFormat = DateTimeComponents.Format {
        year()
        char('-')
        monthNumber()
        char('-')
        dayOfMonth()
        char(' ')
        hour()
        char(':')
        minute()
        char(':')
        second()
        alternativeParsing({}) {
            char(' ')
        }
        alternativeParsing(
            { timeZoneId() },
            { offset(UtcOffset.Formats.ISO) }
        ) {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
            optional {
                char(':')
                offsetSecondsOfMinute()
            }
        }
    }

    private fun format(value: Instant, zone: TimeZone): String {
        return readableFormat.format {
            setDateTime(value.toLocalDateTime(zone))
            timeZoneId = zone.id
        }
    }

    @Test
    fun testReproduction() {
        val value = Instant.parse("2023-10-27T10:00:00Z")
        val zone = TimeZone.of("Europe/Berlin")
        try {
            val result = format(value, zone)
            println("Result: $result")
        } catch (e: Exception) {
            println("Caught exception: $e")
            e.printStackTrace()
            // assertNotNull(e.message)
            // assertTrue(e.message!!.contains("totalHoursAbs is not set"))
            throw e
        }
    }
}
"}

