174→    fun populateFrom(offset: UtcOffset) {
175→        isNegative = offset.totalSeconds < 0
176→        val totalSecondsAbs = offset.totalSeconds.absoluteValue
177→        totalHoursAbs = totalSecondsAbs / 3600
